import { MakeLogicType, kea } from 'kea'
import { router } from 'kea-router'

import api from 'lib/api'
import { lemonToast } from 'lib/lemon-ui/LemonToast'
import { organizationLogic } from 'scenes/organizationLogic'
import { urls } from 'scenes/urls'

import type { OrganizationBasicType } from '~/types'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface userDangerZoneLogicValues {
    _leaveOrganization: null
    _leaveOrganizationLoading: boolean
    deleteUserModalOpen: boolean
    deletedOrganizationIds: string[]
    isUserDeletionConfirmed: boolean
    organizationToDelete: OrganizationBasicType | null
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface userDangerZoneLogicActions {
    deleteOrganizationSuccess: ({ redirectPath }: { redirectPath?: string }) => {
        redirectPath: string | undefined
    } // organizationLogic
    addDeletedOrganizationId: (id: string) => {
        id: string
    }
    leaveOrganization: (organizationId: string) => string
    leaveOrganizationFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    leaveOrganizationSuccess: (
        _leaveOrganization: null,
        payload?: string
    ) => {
        _leaveOrganization: null
        payload?: string
    }
    setDeleteUserModalOpen: (open: boolean) => {
        open: boolean
    }
    setIsUserDeletionConfirmed: (confirmed: boolean) => {
        confirmed: boolean
    }
    setOrganizationToDelete: (organization: OrganizationBasicType | null) => {
        organization: OrganizationBasicType | null
    }
}

export type userDangerZoneLogicType = MakeLogicType<userDangerZoneLogicValues, userDangerZoneLogicActions>

export const userDangerZoneLogic = kea<userDangerZoneLogicType>({
    path: ['scenes', 'settings', 'user', 'userDangerZoneLogic'],
    actions: {
        setDeleteUserModalOpen: (open: boolean) => ({ open }),
        setOrganizationToDelete: (organization: OrganizationBasicType | null) => ({ organization }),
        setIsUserDeletionConfirmed: (confirmed: boolean) => ({ confirmed }),
        addDeletedOrganizationId: (id: string) => ({ id }),
    },
    connect: {
        actions: [organizationLogic, ['deleteOrganizationSuccess']],
    },
    loaders: {
        _leaveOrganization: [
            null,
            {
                leaveOrganization: async (organizationId: string) => {
                    await api.delete(`api/organizations/${organizationId}/members/@me/`)

                    return null
                },
            },
        ],
    },
    reducers: {
        deleteUserModalOpen: [
            false,
            {
                setDeleteUserModalOpen: (_, { open }) => open,
            },
        ],
        organizationToDelete: [
            null as OrganizationBasicType | null,
            {
                setOrganizationToDelete: (_, { organization }) => organization,
            },
        ],
        isUserDeletionConfirmed: [
            false,
            {
                setIsUserDeletionConfirmed: (_, { confirmed }) => confirmed,
            },
        ],
        deletedOrganizationIds: [
            [] as string[],
            {
                addDeletedOrganizationId: (state, { id }) => [...state, id],
                setDeleteUserModalOpen: (state, { open }) => (open ? state : []),
            },
        ],
    },
    listeners: ({ actions, values }) => ({
        setDeleteUserModalOpen: ({ open }) => {
            if (open) {
                router.actions.replace(urls.settings('user-danger-zone'), { deletingUser: true })
            } else {
                router.actions.replace(urls.settings('user-danger-zone'))
            }
        },
        deleteOrganizationSuccess: () => {
            if (values.deleteUserModalOpen && values.organizationToDelete) {
                actions.addDeletedOrganizationId(values.organizationToDelete.id)
                actions.setOrganizationToDelete(null)
            }
        },
        leaveOrganizationSuccess: () => {
            router.actions.replace(urls.settings('user-danger-zone'), { deletingUser: true })

            lemonToast.success('Organization left successfully')

            window.location.reload()
        },
        leaveOrganizationFailure: () => {
            lemonToast.error('Failed to leave organization')
        },
    }),
    urlToAction: ({ actions, values }) => ({
        [urls.settings('user-danger-zone')]: (_, searchParams) => {
            const { deletingUser } = searchParams
            if (deletingUser && !values.deleteUserModalOpen) {
                actions.setDeleteUserModalOpen(true)
            }
        },
    }),
})
